"use client";

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, 
  ArrowLeft, 
  Calendar, 
  Wallet, 
  PieChart, 
  Percent, 
  Loader2,
  AlertCircle,
  TrendingDown
} from 'lucide-react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer
} from 'recharts';

interface TimelineItem {
  month: number;
  totalValue: number;
  accumulatedProfit: number;
}

interface ObliczeniaWynik {
  daily: number;
  weekly: number;
  monthly: number;
  yearly: number;
  total: number;
  duration: string; 
  timeline: TimelineItem[];
}

interface Obligacja {
  symbol: string;
  oprocentowaniePierwszyRok: number;
  okresLata: number;
  kapitalizacja: boolean;
}

function WynikGlownyKafelek({ wyniki, formatPLN }: { wyniki: ObliczeniaWynik, formatPLN: (value: number | undefined) => string }) {
    const gradientStyle = {
        background: 'linear-gradient(135deg, #0071E3 0%, #00C7BE 100%)',
    };

    return (
        <div className="w-full">
            <div 
                style={gradientStyle}
                className="p-6 md:p-8 rounded-[2rem] text-white shadow-xl flex flex-col md:flex-row justify-between items-start md:items-center transform transition-all hover:scale-[1.01]"
            >
                <div className="flex-grow mb-4 md:mb-0">
                    <p className="opacity-90 text-base md:text-lg mb-1 font-medium">
                        Zysk całkowity "na rękę" (netto)
                    </p>
                    <h3 className="text-4xl md:text-5xl font-extrabold tracking-tight">
                        {formatPLN(wyniki.total)}
                    </h3>
                </div>

                <div className="flex items-center space-x-4">
                    <div className="bg-white/20 px-4 py-2 rounded-xl backdrop-blur-sm text-sm font-semibold whitespace-nowrap">
                        <span>Okres: {wyniki.duration}</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

const CustomTooltip = ({ active, payload, label, formatPLN }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white p-4 border border-gray-100 shadow-xl rounded-2xl">
        <p className="text-xs font-bold text-gray-400 uppercase mb-2">Miesiąc {label}</p>
        <p className="text-sm font-bold text-blue-600">Wartość: {formatPLN(payload[0].value)}</p>
        <p className="text-xs text-gray-500 mt-1">Kapitał + Zysk netto</p>
      </div>
    );
  }
  return null;
};

export default function KalkulatorPage() {
  const [kwota, setKwota] = useState<number | ''>(1000);
  const [wybranySymbol, setWybranySymbol] = useState<string>('');
  const [listaObligacji, setListaObligacji] = useState<Obligacja[]>([]);
  const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null); 
  
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [loadingObligacje, setLoadingObligacje] = useState(true);

  const BACKEND_URL = process.env.NEXT_PUBLIC_BACKEND_URL || "http://localhost:8080/api";

  useEffect(() => {
    const fetchObligacje = async () => {
      try {
        const response = await fetch(`${BACKEND_URL}/obligacje`);
        if (!response.ok) throw new Error('Nie udało się pobrać listy obligacji.');
        const data: Obligacja[] = await response.json();
        setListaObligacji(data);
        if (data.length > 0) setWybranySymbol(data[0].symbol);
      } catch (e) {
        setError('Brak połączenia z backendem.');
      } finally {
        setLoadingObligacje(false);
      }
    };
    fetchObligacje();
  }, [BACKEND_URL]);

  const handleOblicz = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!kwota || Number(kwota) <= 0) {
      setError('Podaj poprawną kwotę inwestycji.');
      return;
    }
    setLoading(true);
    try {
      const url = `${BACKEND_URL}/calc?kwota=${kwota}&symbol=${wybranySymbol}`;
      const response = await fetch(url);
      if (!response.ok) throw new Error("Błąd serwera");
      const data: ObliczeniaWynik = await response.json();
      setWyniki(data);
    } catch (e: any) {
      setError('Wystąpił błąd połączenia.');
    } finally {
      setLoading(false);
    }
  };

  const formatPLN = (value: number | undefined) => {
    if (value === undefined || isNaN(value)) return '-';
    return new Intl.NumberFormat('pl-PL', { style: 'currency', currency: 'PLN', minimumFractionDigits: 2 }).format(value);
  };

  const wybranaObligacjaInfo = listaObligacji.find(o => o.symbol === wybranySymbol);

  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] pb-20 font-sans">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-gray-100 px-6 py-4 flex justify-center">
        <div className="w-full max-w-5xl flex justify-between items-center">
            <a href="/" className="flex items-center gap-2 text-gray-500 hover:text-black transition-colors no-underline font-semibold text-sm">
                <ArrowLeft size={18} /> Powrót
            </a>
            <span className="font-bold text-xl tracking-tight flex items-center gap-2">
                <TrendingUp size={22} className="text-[#0071E3]" /> Kalkulator
            </span>
            <div className="w-10"></div> 
        </div>
      </nav>

      <div className="max-w-4xl mx-auto px-6 pt-12">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-extrabold tracking-tight mb-3">Symulacja zysków</h1>
          <p className="text-lg text-gray-500 font-medium">Precyzyjne obliczenia uwzględniające podatek Belki (19%).</p>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 mb-8">
          {loadingObligacje ? (
              <div className="py-12 flex flex-col items-center justify-center text-gray-400">
                <Loader2 className="animate-spin mb-2" /> Pobieranie oferty...
              </div>
          ) : (
          <form onSubmit={handleOblicz} className="space-y-6">
            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-gray-400 mb-3 ml-1">Kwota (PLN)</label>
                <div className="relative">
                  <Wallet size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input
                    type="number"
                    value={kwota}
                    onChange={(e) => setKwota(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-[#F5F5F7] border-none rounded-2xl py-4 pl-12 pr-4 text-xl font-bold focus:ring-2 focus:ring-[#0071E3]/20 transition-all outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-gray-400 mb-3 ml-1">Typ Obligacji</label>
                <div className="relative">
                  <PieChart size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                  <select
                    value={wybranySymbol}
                    onChange={(e) => setWybranySymbol(e.target.value)}
                    className="w-full bg-[#F5F5F7] border-none rounded-2xl py-4 pl-12 pr-4 text-xl font-bold focus:ring-2 focus:ring-[#0071E3]/20 transition-all outline-none appearance-none cursor-pointer"
                  >
                    {listaObligacji.map(o => <option key={o.symbol} value={o.symbol}>{o.symbol}</option>)}
                  </select>
                </div>
              </div>
            </div>

            <button type="submit" disabled={loading} className="w-full bg-[#0071E3] text-white py-5 rounded-2xl font-bold text-xl shadow-lg shadow-blue-600/20 hover:bg-[#005bb5] transition-all flex items-center justify-center gap-3 active:scale-[0.98]">
              {loading ? <Loader2 className="animate-spin" /> : 'Oblicz potencjalny zysk'}
            </button>

            {error && (
              <div className="flex items-center gap-3 p-4 bg-red-50 text-red-600 rounded-2xl border border-red-100">
                <AlertCircle size={20} /> {error}
              </div>
            )}
          </form>
          )}
        </div>

        {wyniki && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <h2 className="text-2xl font-extrabold tracking-tight">Twoja prognoza</h2>
            
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
               <ResultWidget label="Zysk Dzienny" value={formatPLN(wyniki.daily)} />
               <ResultWidget label="Zysk Miesięczny" value={formatPLN(wyniki.monthly)} />
               <ResultWidget label="Zysk Roczny (śr.)" value={formatPLN(wyniki.yearly)} />
               <div className="col-span-1 md:col-span-3">
                   <WynikGlownyKafelek wyniki={wyniki} formatPLN={formatPLN} />
               </div>
            </div>

            {/* WYKRES */}
            <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-lg font-bold">Wzrost kapitału w czasie</h3>
                <TrendingUp className="text-blue-500" size={20} />
              </div>
              <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={wyniki.timeline}>
                    <defs>
                      <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#0071E3" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#0071E3" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F0F0F0" />
                    <XAxis 
                      dataKey="month" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{fill: '#86868b', fontSize: 12}}
                      dy={10}
                    />
                    <YAxis 
                      hide={true}
                      domain={['dataMin - 100', 'dataMax + 100']}
                    />
                    <Tooltip content={<CustomTooltip formatPLN={formatPLN} />} />
                    <Area 
                      type="monotone" 
                      dataKey="totalValue" 
                      stroke="#0071E3" 
                      strokeWidth={3}
                      fillOpacity={1} 
                      fill="url(#colorValue)" 
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* TABELA */}
            <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
              <div className="p-6 border-b border-gray-50 bg-gray-50/50">
                  <h3 className="text-lg font-bold">Harmonogram wzrostu</h3>
              </div>
              <div className="overflow-x-auto">
                  <table className="w-full text-left">
                      <thead>
                          <tr className="bg-gray-50/30 text-[0.65rem] font-black uppercase tracking-widest text-gray-400">
                              <th className="px-8 py-4">Miesiąc</th>
                              <th className="px-8 py-4">Wartość Konta</th>
                              <th className="px-8 py-4 text-right">Zysk Netto</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                          {wyniki.timeline.map((item) => (
                              <tr key={item.month} className="hover:bg-gray-50/50 transition-colors">
                                  <td className="px-8 py-4 font-medium text-gray-500">{item.month}</td>
                                  <td className="px-8 py-4 font-bold">{formatPLN(item.totalValue)}</td>
                                  <td className="px-8 py-4 text-right text-emerald-600 font-extrabold">
                                      +{formatPLN(item.accumulatedProfit)}
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}